        add("bestiary.entity.terra_entity.worm.0.desc", "Worms infused with fallen star magic glow with a glittering light. Fish are extremely attracted to these.");
        add("bestiary.entity.terra_entity.fairy.0.desc", "Glowing winged humanoid creatures the size of a butterfly. Attuned to the world around them, they excel at finding shiny things.");
