        add("bestiary.entity.terra_entity.blood_zombie.desc", "With enough exposure to a Blood Moon, zombies become twisted and cursed with everflowing blood pouring out from their rotten flesh.");
//        add("bestiary.entity.terra_entity.the_groom.desc", "Tall, handsome, and dead. This unlucky fellow did not survive his wedding and is ready to take it out on everyone.");
        add("bestiary.entity.terra_entity.the_bride.desc", "It's uncertain if the bride was wed before or after her death, but the story ends tragically for anyone who crosses her path.");
