        add("bestiary.entity.terra_entity.drippler.desc", "Demon eyes become erratic under a Blood Moon, sometimes twisting together into a dripping cluster of cursed blood and eyeballs.");
//        add("bestiary.entity.terra_entity.chattering_teeth_bomb.desc", "A playful prank gone wrong, clowns will unleash these explosive chompers on their enemies. Also great for parties!");
        add("bestiary.entity.terra_entity.wandering_eye_fish.desc", "For mysterious reasons, fish are known to mutate with other living things or even man-made objects. This one is especially violent.");
