        add("bestiary.confluence.filter.granite.title", "花岗岩");
        add("bestiary.confluence.filter.granite.desc", "花岗岩洞是一种出现在地下或洞穴层的迷你生物群系。");
        add("bestiary.confluence.filter.the_temple.title", "神庙");
