        add("bestiary.confluence.filter.eclipse.title", "日食");
        add("bestiary.confluence.filter.eclipse.desc", "日食是个困难模式事件，在至少有一个机械 Boss 被打败后会偶有发生。日食在任何特定黎明都有几率发生。");
        add("bestiary.confluence.filter.rain.title", "下雨");
        add("bestiary.confluence.filter.rain.desc", "雨是一个事件，在其持续时间内会影响所有地表生物群系。");
        add("bestiary.confluence.filter.windy_day.title", "大风天");
        add("bestiary.confluence.filter.windy_day.desc", "大风天是当风速超过 20 mph 时发生的一个事件。");
        add("bestiary.confluence.filter.blizzard.title", "暴风雪");
        add("bestiary.confluence.filter.blizzard.desc", "在下雨期间位于雪原生物群系中时，它会以暴雪的形式呈现，导致降雪量增加。");
        add("bestiary.confluence.filter.sandstorm.title", "沙尘暴");
        add("bestiary.confluence.filter.sandstorm.desc", "沙尘暴是一个专属于沙漠的事件，会同时在所有的沙漠中发生。");
        add("bestiary.confluence.filter.meteor.title", "陨石");
        add("bestiary.confluence.filter.meteor.desc", "陨石生物群系是一种迷你生物群系，形成于流星坠落在世界中时。");
        add("bestiary.confluence.filter.halloween.title", "万圣节");
