        add("bestiary.confluence.filter.christmas.title", "圣诞节");
        add("bestiary.confluence.filter.christmas.desc", "圣诞节是一个开始于十二月中旬结束于一月初的季节性事件。");
        add("bestiary.confluence.filter.party.title", "派对");
        add("bestiary.confluence.filter.party.desc", "派对是一个事件，可以随机发生，或者用派对中心手动激活。");
        add("bestiary.confluence.filter.goblin_invasion.title", "哥布林入侵");
        add("bestiary.confluence.filter.goblin_invasion.desc", "哥布林军队（也称为哥布林入侵）是一个入侵事件，会使得独特的哥布林敌怪代替常规敌怪生成。");
        add("bestiary.confluence.filter.pirate_invasion.title", "海盗入侵");
        add("bestiary.confluence.filter.pirate_invasion.desc", "海盗入侵是一个困难模式入侵事件，会使得海盗主题的敌怪代替常规敌怪生成。");
        add("bestiary.confluence.filter.pumpkin_moon.title", "南瓜月");
        add("bestiary.confluence.filter.pumpkin_moon.desc", "南瓜月是一个困难模式，世纪之花之后的以万圣节为主题的事件");
        add("bestiary.confluence.filter.frost_moon.title", "霜月");
        add("bestiary.confluence.filter.frost_moon.desc", "霜月是一种困难模式，世纪之花后的，以圣诞节为主题的事件");
        add("bestiary.confluence.filter.martian_madness.title", "火星暴乱");
        add("bestiary.confluence.filter.martian_madness.desc", "火星暴乱是一个困难模式、石巨人后的入侵事件，会使得独特的外星人主题的敌怪代替常规敌怪生成。");
        add("bestiary.confluence.filter.frost_legion.title", "雪人军团");
        add("bestiary.confluence.filter.frost_legion.desc", "雪人军团是一个困难模式入侵事件，会使得独特的雪人敌怪代替常规敌怪生成。");
        add("bestiary.confluence.filter.old_ones_army.title", "撒旦军队");
        add("bestiary.confluence.filter.old_ones_army.desc", "撒旦军队是个独特的《地牢守护者 2》（Dungeon Defenders 2）联动事件");
        add("bestiary.confluence.filter.solar_pillar.title", "日耀柱");
        add("bestiary.confluence.filter.solar_pillar.desc", "日耀柱是近战主题的天界柱。");
        add("bestiary.confluence.filter.vortex_pillar.title", "星旋柱");
        add("bestiary.confluence.filter.vortex_pillar.desc", "星旋柱是远程主题的天界柱。");
        add("bestiary.confluence.filter.nebula_pillar.title", "星云柱");
        add("bestiary.confluence.filter.nebula_pillar.desc", "星云柱是魔法主题的天界柱。");
        add("bestiary.confluence.filter.stardust_pillar.title", "星尘柱");
        add("bestiary.confluence.filter.stardust_pillar.desc", "星尘柱是召唤主题的天界柱。");
        add("bestiary.confluence.filter.if_unlocked.title", "已解锁");
        add("bestiary.confluence.filter.if_unlocked.desc", "已解锁");
        add("bestiary.confluence.filter.boss_enemy.title", "敌方Boss");
        add("bestiary.confluence.filter.boss_enemy.desc", "Boss 是富有攻击性且强韧的敌怪，向玩家提出了重大挑战。");
        add("bestiary.confluence.filter.rare_creature.title", "稀有生物");
        add("bestiary.confluence.filter.rare_creature.desc", "这种生物很稀有");

        add("bestiary.entity.terra_entity.guide.desc", "向导总是提供有用的建议和制作配方。他的出身以及他与这个世界非同寻常的联系仍然是一个谜。");
        add("bestiary.entity.terra_entity.merchant.desc", "商人就像一个简单的杂货店，提供有用的新手工具和探索所需的物资。");
        add("bestiary.entity.terra_entity.nurse.desc", "护士的刻薄态度和糟糕的护理方式可能会让人害怕，但只要付出一定的代价，她就能完全治愈受创的泰拉瑞亚人。");
        add("bestiary.entity.terra_entity.demolitionist.desc", "在这个矮人周围要小心。爆破专家痴迷于炸药，兜售的都是会“砰！”的危险物品。");
        add("bestiary.entity.terra_entity.angler.desc", "渔夫是粗鲁的钓鱼天才，叫人去寻找稀有怪鱼。他会随机奖励物品，从他人的不幸中取乐。");
        add("bestiary.entity.terra_entity.dryad.desc", "树妖是她的同族中最后一人了。她与大自然紧密相连，可以分析世界各地的自然纯净度。她还售卖种子！");
        add("bestiary.entity.terra_entity.arms_dealer.desc", "军火商拥有所有致命武器，小到一枚子弹，大到用鲨鱼制成的枪炮。");
        add("bestiary.entity.terra_entity.dye_trader.desc", "染料商古怪且势利到极点，他有着奢侈的爱好。他对自己销售的染料所用的材料很感兴趣。");
        add("bestiary.entity.terra_entity.painter.desc", "关于刷墙的油漆，这名油漆工可以就各种颜色大谈特谈一番。但他只售卖其中一小部分油漆！");
//         add("bestiary.entity.terra_entity.stylist.desc", "发型师钟爱时尚、八卦和发型。除了帮人进行神奇大改造，她还售卖一些美发产品。");
        add("bestiary.entity.terra_entity.zoologist.desc", "动物学家是定居于此的兽化人，她非常喜欢动物。她那狐狸般的生理状况是由被诅咒的动物咬伤所致。");
//         add("bestiary.entity.terra_entity.tavernkeep.desc", "这个酒馆老板曾在另一个世界经营着酒吧。他来这里是为了阻止撒旦军队征服这个世界。");
//         add("bestiary.entity.terra_entity.golfer.desc", "高尔夫球手是睿智的中年男子，出售各种高尔夫设备。他拿下了许多比赛，知道如何得分。");
        add("bestiary.entity.terra_entity.goblin_tinkerer.desc", "这名工匠由于是一个聪明的和平主义者而遭到其他哥布林成员的驱逐，他出售用来将配饰组装成更强版本的工具。");
        add("bestiary.entity.terra_entity.witch_doctor.desc", "丛林蜥蜴待在神庙之外可不寻常。更不寻常的是他出售的巫毒物品。他更喜欢他在丛林的家。");
        add("bestiary.entity.terra_entity.mechanic.desc", "机械师因在工程方面的才能而被监禁。她出售电线和工具，用来组装任何可以想象的东西。");
        add("bestiary.entity.terra_entity.clothier.desc", "服装商曾被诅咒所困，是当之无愧的针线大师。若你追求时尚，找他准没错！他说话的语气十分随和。");
        add("bestiary.entity.terra_entity.wizard.desc", "巫师是个精神恍惚又有些癫狂的健忘老人，醉心于奥术研究。他售卖魔法小饰品，以此培养新的学徒。");
//        add("bestiary.entity.terra_entity.steampunker.desc", "蒸汽朋克人对蒸汽驱动的机械与装置情有独钟。她带着可爱的口音，售卖自己发明的各类小玩意儿。");
//        add("bestiary.entity.terra_entity.pirate.desc", "喂！唯一像样的海盗船长是……那种卖大炮和武器，用来干掉所有竞争对手船长的人！");
        add("bestiary.entity.terra_entity.truffle.desc", "松露人能驾驭发光蘑菇的隐藏力量，只在自己的蘑菇屋里打造武器与工具。");
//        add("bestiary.entity.terra_entity.tax_collector.desc", "这位脾气暴躁的税收官可是真真切切从地狱走了一遭又回来的。他贪婪到了极点，心里真正在乎的只有钱。");
//        add("bestiary.entity.terra_entity.cyborg.desc", "机器侠是机械师与蒸汽朋克人联手打造的产物，旨在为火箭研发与世界防御提供助力。");
        add("bestiary.entity.terra_entity.party_girl.desc", "派对女孩的乐观简直超乎想象，她总能找到借口举办庆祝活动。她售卖派对用品和各种亮眼的小物件。");
//        add("bestiary.entity.terra_entity.princess.desc", "这位可爱的年轻公主腼腆又纯真，看待万物与人都能发现积极的一面。她珍视来自各行各业的每一位子民。");
//        add("bestiary.entity.terra_entity.santa_claus.desc", "圣诞老人只在一年中的特定时段出现，他登场时场面盛大，退场时更是热闹——甚至带着点“爆炸性”。嚯！嚯！嚯！");
//        add("bestiary.entity.terra_entity.town_cat.desc", "城镇猫咪又懒又狡黠，说不定会带来礼物。只不过那些礼物，或许曾经是活物。");
//        add("bestiary.entity.terra_entity.town_dog.desc", "城镇狗狗是许多人的忠实伙伴，性子活泼，随时准备行动。");
//        add("bestiary.entity.terra_entity.town_bunny.desc", "城镇兔兔保证能管好蔬菜供应，不过，它也有可能被做成帽子。");
//        add("bestiary.entity.terra_entity.nerdy_slime.desc", "书呆子史莱姆只比其他史莱姆聪明一点点，却摸索出了与人类共存的方法。秘诀就是：搭配饰品！");
//        add("bestiary.entity.terra_entity.cool_slime.desc", "酷酷史莱姆无疑是最“酷”的史莱姆，这点毫无争议。从它反戴的帽子和让人摸不着头脑的俚语就能看出来。");
//        add("bestiary.entity.terra_entity.elder_slime.desc", "长者史莱姆年纪更大，却未必更聪明，但其他史莱姆都很敬重它。能活这么久，它肯定有过人之处！");
//        add("bestiary.entity.terra_entity.clumsy_slime.desc", "当其他史莱姆开始戴帽子、配饰品时，笨拙史莱姆还一脸困惑。但它已经尽力去跟上大家了。");
//        add("bestiary.entity.terra_entity.diva_slime.desc", "天后史莱姆由微光与史莱姆皇后的能量融合而生，充满了无限活力与热情！而且模样格外精致！");
//        add("bestiary.entity.terra_entity.surly_slime.desc", "暴躁史莱姆脾气坏、惹人厌，说不定没什么好心眼。或许吧。不过重要的是这份“可能”的心意（才怪）。");
//        add("bestiary.entity.terra_entity.mystic_slime.desc", "神秘史莱姆知道，强大的女巫都戴着气派的帽子，可它只找到一顶耷拉的软帽。难怪它的变形术总是弄巧成拙！");
//        add("bestiary.entity.terra_entity.squire_slime.desc", "侍卫史莱姆是史莱姆中的英雄，手持同类中最厉害的武器与盔甲。虽然它还不知道怎么用，但也算迈出了第一步。");
        add("bestiary.entity.terra_entity.traveling_merchant.desc", "衣着华丽的旅行商人走遍四方，时常带来独具特色的各地商品。");
//        add("bestiary.entity.terra_entity.skeleton_merchant.desc", "大多数骷髅都嗜杀成性，但骷髅商人不一样。他只想售卖物资，比如稀有火把和悠悠球装备。");
        add("bestiary.entity.terra_entity.old_man.desc", "这个不幸的老人背负着沉重的诅咒。据说一到夜晚，他就会变成守护地牢的恐怖恶魔。");
//        add("bestiary.entity.terra_entity.mystic_frog.desc", "神秘青蛙戴着滑稽的帽子，周身环绕着强大的魔法！或许有东西能解除它的诅咒……但你大概不该亲吻它！");
        add("bestiary.entity.terra_entity.bunny.desc", "兔兔是毛茸茸的小家伙，偏爱安全、友善的环境。");
//        add("bestiary.entity.terra_entity.bunny_with_a_hat.desc", "有人给这只兔兔戴了顶派对帽，看来它肯定是个派对狂热爱好者。");
        add("bestiary.entity.terra_entity.explosive_bunny.desc", "爆炸兔可不是普通的田园兔子，它被人动过手脚，脾气火爆得很。");
//        add("bestiary.entity.terra_entity.bunny_slime.desc", "这是穿了史莱姆外套的兔子，还是穿了兔子外套的史莱姆？万圣节有时候就是这么让人摸不着头脑。");
//        add("bestiary.entity.terra_entity.bunny_xmas.desc", "从装扮来看，圣诞老人今年似乎找了些兔子来当他的小帮手。");
        add("bestiary.entity.terra_entity.jewel_bunny.4.desc", "罕见情况下，有些小动物会全身覆金！店主们愿意出高价收购，你也可以把它们关在笼子里炫耀！");
        add("bestiary.entity.terra_entity.bird.desc", "普通的白色小鸟，喜欢风和日丽的好天气。");
        add("bestiary.entity.terra_entity.blue_jay.desc", "这只蓝色的小鸟是来捉蠕虫的。");
        add("bestiary.entity.terra_entity.cardinal.desc", "红雀是罕见的红冠鸟类，堪称森林的好朋友。");
//        add("bestiary.entity.terra_entity.scarlet_macaw.desc", "绯红金刚鹦鹉是可爱的热带鸟类，羽毛色彩让人想起丛林树冠上空的绝美日落。");
//        add("bestiary.entity.terra_entity.blue_macaw.desc", "蓝金刚鹦鹉常在丛林的树上觅食种子，它的模样会让人联想到夏日晴空下晶莹湛蓝的海水。");
//        add("bestiary.entity.terra_entity.toucan.desc", "巨嘴鸟羽毛鲜艳、鸟喙宽大，你常会看到它在高高的树枝间盘旋，寻找美味的果实。");
//        add("bestiary.entity.terra_entity.yellow_cockatiel.desc", "黄玄凤鹦鹉羽冠上的特殊羽毛能反映它的情绪，通常在兴奋时，羽冠会竖起来。");
//        add("bestiary.entity.terra_entity.gray_cockatiel.desc", "灰玄凤鹦鹉是鹦鹉的近亲，天生喜欢社交，通常能学会说一些简单的短语。");
//      add("bestiary.entity.terra_entity.gold_bird.desc", "罕见情况下，有些小动物会全身覆金！店主们愿意出高价收购，你也可以把它们关在笼子里炫耀！");
