        add("bestiary.entity.terra_entity.ladybug.1.desc", "瓢虫是亮红色的昆虫，常被视为好运的象征。但用它们当鱼饵钓鱼，可能会招来不好的运气。");
        add("bestiary.entity.terra_entity.ladybug.0.desc", "罕见情况下，有些小动物会全身覆金！店主们会出高价收购，而且鱼儿超爱金色的鱼饵！");
//        add("bestiary.entity.terra_entity.stinkbug.desc", "臭虫是鬼祟的害虫，就算是密不透风的房子，它们也能钻进去；一旦受到干扰，就会散发出类似香菜的臭味，弥漫各处。");
        add("bestiary.entity.terra_entity.fealing.0.desc", "当动物误入微光池塘发光的深处时，就会孕育出飞灵这种闪闪发光、形似仙灵的生物。");
        add("bestiary.entity.terra_entity.duck.0.desc", "野鸭是拥有漂亮羽毛的水禽，喜欢在最纯净的水中游动，还会欢快地嘎嘎叫。");
        add("bestiary.entity.terra_entity.duck.1.desc", "鸭子是白色羽毛的水禽，喜欢在纯净的水中游动，沐浴温暖的阳光。");
//        add("bestiary.entity.terra_entity.turtle.desc", "乌龟行动缓慢、性情沉稳，在湖泊与陆地之间往返活动，背上坚硬的龟壳是它们的保护盾。");
//        add("bestiary.entity.terra_entity.owl.desc", "猫头鹰是聪明的大型猛禽，夜间会在树顶捕食。");
//        add("bestiary.entity.terra_entity.firefly.desc", "萤火虫夜晚会出现在安静的地方，用闪烁的绿光点亮夜空。鱼儿会被它们吸引。");
        add("bestiary.entity.terra_entity.worm.0.desc", "附魔夜行者是注入了坠落之星魔法的蠕虫，散发着耀眼的光芒，对鱼儿有着极强的吸引力。");
        add("bestiary.entity.terra_entity.fairy.0.desc", "粉仙灵是蝴蝶大小的发光有翼人形生物，能与周围环境相融，擅长寻找闪亮的物品。");
        add("bestiary.entity.terra_entity.fairy.1.desc", "绿仙灵是蝴蝶大小的发光有翼人形生物，能与周围环境相融，擅长寻找闪亮的物品。");
        add("bestiary.entity.terra_entity.fairy.2.desc", "蓝仙灵是蝴蝶大小的发光有翼人形生物，能与周围环境相融，擅长寻找闪亮的物品。");
//        add("bestiary.entity.terra_entity.rat.desc", "大鼠是长毛啮齿动物，会在腐烂的地方嗅来嗅去寻找食物。人们都躲着它们，生怕感染它们可能携带的疾病。");
        add("bestiary.entity.terra_entity.maggot.desc", "蝇蛆是令人不适的幼虫，以腐烂的尸体为食。鱼儿多少会被它们吸引。");
        add("bestiary.entity.terra_entity.jewel_squirrel.2.desc", "紫晶松鼠因迷途过深，被宝石中残留的诅咒能量所迷惑，身体变得闪闪发光。");
        add("bestiary.entity.terra_entity.jewel_squirrel.7.desc", "黄玉松鼠因迷途过深，被宝石中残留的诅咒能量所迷惑，身体变得闪闪发光。");
        add("bestiary.entity.terra_entity.jewel_squirrel.6.desc", "蓝玉松鼠因迷途过深，被宝石中残留的诅咒能量所迷惑，身体变得闪闪发光。");
        add("bestiary.entity.terra_entity.jewel_squirrel.4.desc", "翡翠松鼠因迷途过深，被宝石中残留的诅咒能量所迷惑，身体变得闪闪发光。");
        add("bestiary.entity.terra_entity.jewel_squirrel.5.desc", "红玉松鼠因迷途过深，被宝石中残留的诅咒能量所迷惑，身体变得闪闪发光。");
        add("bestiary.entity.terra_entity.jewel_squirrel.3.desc", "钻石松鼠因迷途过深，被宝石中残留的诅咒能量所迷惑，身体变得闪闪发光。");
        add("bestiary.entity.terra_entity.jewel_squirrel.0.desc", "琥珀松鼠因迷途过深，被宝石中残留的诅咒能量所迷惑，身体变得闪闪发光。");
        add("bestiary.entity.terra_entity.jewel_bunny.1.desc", "紫晶兔兔躲得极深，接触到魔法宝石后，身体呈现出令人喜爱的闪亮模样。");
        add("bestiary.entity.terra_entity.jewel_bunny.7.desc", "黄玉兔兔躲得极深，接触到魔法宝石后，身体呈现出令人喜爱的闪亮模样。");
        add("bestiary.entity.terra_entity.jewel_bunny.6.desc", "蓝玉兔兔躲得极深，接触到魔法宝石后，身体呈现出令人喜爱的闪亮模样。");
        add("bestiary.entity.terra_entity.jewel_bunny.3.desc", "翡翠兔兔躲得极深，接触到魔法宝石后，身体呈现出令人喜爱的闪亮模样。");
        add("bestiary.entity.terra_entity.jewel_bunny.5.desc", "红玉兔兔躲得极深，接触到魔法宝石后，身体呈现出令人喜爱的闪亮模样。");
        add("bestiary.entity.terra_entity.jewel_bunny.2.desc", "钻石兔兔躲得极深，接触到魔法宝石后，身体呈现出令人喜爱的闪亮模样。");
        add("bestiary.entity.terra_entity.jewel_bunny.0.desc", "琥珀兔兔躲得极深，接触到魔法宝石后，身体呈现出令人喜爱的闪亮模样。");
        add("bestiary.entity.terra_entity.snail.desc", "蜗牛是黏糊糊的软体动物，生活在潮湿、黑暗的地方。鱼儿几乎不会被它们吸引。");
//        add("bestiary.entity.terra_entity.truffle_worm.desc", "松露虫是极其稀有、难以捕捉的发光蠕虫，有一种特定的强大海洋生物对它情有独钟。");
//        add("bestiary.entity.terra_entity.penguin.desc", "企鹅在世界上最寒冷的地区安家，摇摇摆摆地四处寻找美味的鱼儿。");
//        add("bestiary.entity.terra_entity.penguin_black.desc", "黑企鹅在世界上最寒冷的地区安家，摇摇摆摆地四处寻找美味的鱼儿。");
        add("bestiary.entity.terra_entity.scorpion.1.desc", "蝎子在沙漠中无害地四处觅食。鱼儿几乎不会被它们吸引。");
        add("bestiary.entity.terra_entity.scorpion.0.desc", "黑蝎子虽然外表吓人，但除非受到威胁或面对小型猎物，否则性情相当温顺。鱼儿偶尔会被它们吸引。");
//        add("bestiary.entity.terra_entity.grebe.desc", "䴙䴘是在沙漠绿洲中繁衍生息的奇异水禽。");
//        add("bestiary.entity.terra_entity.pupfish.desc", "鳉鱼偏爱竞争较少的孤立极端环境，比如沙漠绿洲的湖床。");
//        add("bestiary.entity.terra_entity.jungle_turtle.desc", "丛林龟坚硬的甲壳能与它们栖息的茂密丛林环境相融，以此伪装自己，躲避凶恶捕食者的攻击。");
        add("bestiary.entity.terra_entity.grubby.desc", "蛆虫黏糊糊的，却很受鱼儿青睐！鱼儿多少会被它们吸引。");
        add("bestiary.entity.terra_entity.sluggy.desc", "鼻涕虫行动缓慢，全身覆盖着光滑黏液。鱼儿特别容易被它们吸引。");
//        add("bestiary.entity.terra_entity.buggy.desc", "蚜虫是一种色彩鲜艳的甲虫类昆虫。它们对鱼儿有着极强的吸引力。");
//        add("bestiary.entity.terra_entity.lavafly.desc", "熔岩萤火虫是萤火虫的变种，适应了世界地狱核心的极端环境，外形酷似闪烁的余烬。");
        add("bestiary.entity.terra_entity.hell_butterfly.desc", "地狱蝴蝶是在地狱中寻觅绽放花朵的冷峻生灵，翅膀上的火红翅脉闪烁着微光。");
        add("bestiary.entity.terra_entity.magma_snail.desc", "岩浆蜗牛是能承受极端高温的独特蜗牛品种，其沸腾的黏液轨迹能融化大多数较脆弱的表面。");
//        add("bestiary.entity.terra_entity.lightning_bug.desc", "荧光虫夜晚出现在福佑之地，闪烁的蓝绿光芒点亮夜空。鱼儿特别容易被它们吸引。");
        add("bestiary.entity.terra_entity.prismatic_lacewing.desc", "传说若一只七彩草蛉这样的发光生物在夜晚的混乱中死亡，某个沉睡的暴君便会被猛烈唤醒。");
        add("bestiary.entity.terra_entity.glowing_snail.desc", "发光蜗牛是为适应发光蘑菇环境而发生变异的蜗牛品种，鱼儿对它们的吸引力相当大。");
//        add("bestiary.entity.terra_entity.gnome.desc", "侏儒是长着长胡子的小巧地精，居住在高大的树木中。一旦暴露在阳光下，就会变成草坪装饰。");
        add("bestiary.entity.terra_entity.goblin_scout.desc", "哥布林军队会从海滩派出单独的侦察兵，搜寻可征服的聚落，它们会用破旧的徽章发出警示信号。");
        add("bestiary.entity.terra_entity.goblin_peon.desc", "这些丑恶的生物是哥布林军队的普通步兵，它们不过就是炮灰……和替死鬼。");
        add("bestiary.entity.terra_entity.goblin_thief.desc", "这些恼人的敌人擅长敏捷移动和近身作战，是哥布林军队的快速打击小队。");
        add("bestiary.entity.terra_entity.goblin_archer.desc", "弓箭手会保持距离为哥布林军队提供远程支援，帮助他们分散敌人的注意力，杀敌人一个措手不及。");
        add("bestiary.entity.terra_entity.goblin_warrior.desc", "这些全副武装的士兵是哥布林军队的步兵骨干，它们可以毫不畏惧地顶着巨大的伤害行进。");
        add("bestiary.entity.terra_entity.goblin_sorcerer.desc", "尽管哥布林相当落后，但有些哥布林却能通过施法操纵魔化的暗影能量。");
        add("bestiary.entity.terra_entity.anger_goblin.desc", "这种哥布林疑似带着战神般的愤怒，实力强悍。");
        add("bestiary.entity.terra_entity.green_slime.desc", "绿史莱姆是简单的胶状生物，见到任何东西都会整个吞下！但消化过程需要很长时间。");
        add("bestiary.entity.terra_entity.blue_slime.desc", "蓝史莱姆是简单的胶状生物，见到任何东西都会整个吞下！但消化过程需要很长时间。");
        add("bestiary.entity.terra_entity.purple_slime.desc", "紫史莱姆是简单的胶状生物，见到任何东西都会整个吞下！但消化过程需要很长时间。");
        add("bestiary.entity.terra_entity.pink_slime.desc", "粉史莱姆是有记录以来最小的史莱姆，其极高的细胞密度让小巧的体型拥有了惊人的耐用性。它们以钱币为食。");
        add("bestiary.entity.terra_entity.golden_slime.desc", "传说世界上有一种吃了太多钱币的史莱姆，是财富与运气的象征。");
        add("bestiary.entity.terra_entity.honey_slime.desc", "有的黄蜂发现，不小心掉入蜂蜜中的史莱姆会变得更加可口。于是蜂群有时候会养殖这种史莱姆。");
        add("bestiary.entity.terra_entity.swamp_slime.desc", "由于陷入沼泽的人不在少数，导致了这里的原生史莱姆看上去特别骇人。");
        add("bestiary.entity.terra_entity.green_dumpling_slime.desc", "吞噬了各种草药和艾草的史莱姆，会在一年中特定的节日中出现。");
        add("bestiary.entity.terra_entity.spiked_slime.desc", "史莱姆王分裂出更具有攻击性的个体以保护自己。它们会发射出独特的硬化尖刺。");
        add("bestiary.entity.terra_entity.tropic_slime.desc", "在白天的海滩旁，热带史莱姆们会出来晒晒体内的热带鱼。");
//        add("bestiary.entity.terra_entity.windy_balloon.desc", "有些胆大的史莱姆会借助气球乘着气流飞行，寻找食物。击破它们的气球就能让其落回地面。");
//        add("bestiary.entity.terra_entity.angry_dandelion.desc", "强风足以让几乎所有生物烦躁，显然，原本无害的蒲公英也不例外——它们会射出致命的种子。");
//        add("bestiary.entity.terra_entity.umbrella_slime.desc", "这把雨伞的前主人吸取了惨痛教训：雨伞能有效防雨，却防不住史莱姆。");
        add("bestiary.entity.terra_entity.flying_fish.desc", "某些鱼类在雨天会获得奇特的能力。对于陆地上的生物，它们只对一样东西感兴趣——血肉。");
//        add("bestiary.entity.terra_entity.angry_nimbus.desc", "据说暴风雨来临时，天空会“发怒”，而这团愤怒雨云怪的“怒气”尤为强烈！");
        add("bestiary.entity.terra_entity.demon_eye.dilated.desc", "当克苏鲁的涣散仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.dilated_small.desc", "当克苏鲁的涣散小仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.sleepy.desc", "当克苏鲁的瞌睡仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.sleepy_big.desc", "当克苏鲁的大瞌睡仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.purple.desc", "当克苏鲁的紫色仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.purple_big.desc", "当克苏鲁的紫色大仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.normal.desc", "当克苏鲁的仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.normal_big.desc", "当克苏鲁的大仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.green.desc", "当克苏鲁的绿色仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.green_small.desc", "当克苏鲁的绿色小仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.cataract.desc", "当克苏鲁的老仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.demon_eye.cataract_big.desc", "当克苏鲁的大型老仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
        add("bestiary.entity.terra_entity.wandering_eye.desc", "当克苏鲁的仆从在漆黑的夜晚盘旋空中时，那种被人监视的不安感，很可能是真实存在的。");
//      add("bestiary.entity.terra_entity.zombie_female.desc", "敞着门可能会让蹒跚的食脑僵尸闯入家中，没人愿意遇到这种事。");
        add("bestiary.entity.minecraft.zombie.slime.desc", "有时，史莱姆的猎物在被消化的过程中会变成僵尸。这样“半消化半僵尸”地四处游荡，对双方来说都很尴尬。");
//      add("bestiary.entity.terra_entity.zombie_bald.desc", "敞着门可能会让蹒跚的食脑僵尸闯入家中，没人愿意遇到这种事。");
        add("bestiary.entity.minecraft.zombie.desc", "敞着门可能会让蹒跚的食脑僵尸闯入家中，没人愿意遇到这种事。");
//      add("bestiary.entity.terra_entity.zombie_twiggy.desc", "敞着门可能会让蹒跚的食脑僵尸闯入家中，没人愿意遇到这种事。");
