//      add("bestiary.entity.terra_entity.zombie_swamp.desc", "敞着门可能会让蹒跚的食脑僵尸闯入家中，没人愿意遇到这种事。");
//      add("bestiary.entity.terra_entity.zombie_pincushion.desc", "敞着门可能会让蹒跚的食脑僵尸闯入家中，没人愿意遇到这种事。");
        add("bestiary.entity.minecraft.zombie.raincoat.desc", "有些僵尸出门必穿可靠的雨衣，无论天气如何，它们都会在舒适干爽的状态下追逐人肉。");
        add("bestiary.entity.terra_entity.possess_armor.desc", "究竟是什么东西附身于这套盔甲，让它突然能动弹并开始滥杀无辜？它连实体都没有啊。");
//        add("bestiary.entity.terra_entity.werewolf.desc", "狼人受月光诅咒，这些凶恶的 lupine（ lupine：此处指“狼形生物” ）曾是人类，如今却会本能地捕食自己的亲人。");
        add("bestiary.entity.terra_entity.wraith.desc", "拥有最黑暗心灵的灵魂曾被封印在世界核心，如今它们在夜间游荡，寻找新的成员壮大自己的族群。");
//        add("bestiary.entity.terra_entity.corrupt_bunny.desc", "兔兔本是纯洁的生物，通常能抵抗各种腐化力量，但在血月影响下会屈服。");
//        add("bestiary.entity.terra_entity.corrupt_penguin.desc", "血月期间，原本温顺的企鹅会受到腐化力量的敌意影响，变得极具攻击性。");
//        add("bestiary.entity.terra_entity.vicious_bunny.desc", "兔兔本是纯洁的生物，通常不会被猩红感染，但在血月影响下会屈服。");
//        add("bestiary.entity.terra_entity.vicious_penguin.desc", "血月期间，原本温顺的企鹅会被猩红的传染性增生所侵蚀。");
        add("bestiary.entity.terra_entity.blood_zombie.desc", "长时间暴露在血月下，僵尸会发生扭曲并被诅咒，腐烂的肉体中不断涌出鲜血。");
//        add("bestiary.entity.terra_entity.the_groom.desc", "僵尸新郎高大英俊，却早已死亡。这位不幸的家伙没能熬过自己的婚礼，如今准备向所有人发泄怒火。");
        add("bestiary.entity.terra_entity.the_bride.desc", "没人知道僵尸新娘是生前还是死后结的婚，但所有与她相遇的人，结局都很悲惨。");
//        add("bestiary.entity.terra_entity.zombie_merman.desc", "人鱼或许是稀有奇特的亚人，但他们仍会死亡……死后还会以不同的形态回归。");
//        add("bestiary.entity.terra_entity.clown.desc", "小丑的来历成谜，这个令人毛骨悚然的恶魔踩着球保持平衡，同时向周围所有事物投掷爆炸物。");
//        add("bestiary.entity.terra_entity.blood_squid.desc", "血乌贼会被鹦鹉螺小规模召唤，协助主人战斗，它们的身体会喷涌出浓稠的血流。");
//        add("bestiary.entity.terra_entity.blood_eel.desc", "血鳗鱼是体型庞大的蠕虫状恶魔，浑身滴着鲜血——既有自己的，也有受害者的。它简直是一场血腥的噩梦！");
//        add("bestiary.entity.terra_entity.corrupt_goldfish.desc", "金鱼在血月影响下会发生变异，变得狂暴并被腐化力量控制。");
//        add("bestiary.entity.terra_entity.vicious_goldfish.desc", "金鱼在血月影响下会变成猩红的畸形吸血恶魔。");
        add("bestiary.entity.terra_entity.drippler.desc", "血月期间，恶魔眼会变得异常，有时会缠绕在一起，形成由被诅咒的血液和眼球组成的滴血团块——这就是滴滴怪。");
//        add("bestiary.entity.terra_entity.chattering_teeth_bomb.desc", "嗒嗒牙齿炸弹本是一场失控的恶作剧，小丑会将这些会爆炸的“牙齿”扔向敌人，不过用来活跃派对气氛也不错！");
        add("bestiary.entity.terra_entity.wandering_eye_fish.desc", "出于神秘原因，鱼类会与其他生物甚至人造物品发生融合变异，而这只游荡眼球怪鱼格外凶猛。");
//        add("bestiary.entity.terra_entity.hemogoblin_shark.desc", "血浆哥布林鲨鱼半是鲨鱼半是哥布林，极度凶残！这是血月期间最好待在家里的众多理由之一。");
//        add("bestiary.entity.terra_entity.dreadnautilus.desc", "恐惧鹦鹉螺是体型巨大的带壳水恶魔，以血月的负能量为食，若受到打扰，会发起残酷的反击。");
//        add("bestiary.entity.terra_entity.hoppin_jack.desc", "弹跳杰克南瓜灯因被雕刻而怀恨在心，它被雕刻得越厉害，跳跃速度就越快。");
//        add("bestiary.entity.terra_entity.maggot_zombie.desc", "蝇蛆僵尸漫无目的地游荡，试图将生者感染成亡灵，却没意识到自己早已被蛆虫寄生。");
//        add("bestiary.entity.terra_entity.raven.desc", "乌鸦只会反复鸣叫：“永不复焉”。永不复焉。永不复焉。永不复焉。永不复焉。永不复焉。永不复焉。永不复焉。");
        add("bestiary.entity.terra_entity.ghost.desc", "在最痛苦的时刻，这些鬼魂会在深处漫无目的地飘荡，从自己嫉妒的生灵身上窃取生命。");
        add("bestiary.entity.terra_entity.red_slime.desc", "红史莱姆是简单的胶状生物，见到任何东西都会整个吞下！但消化过程需要很长时间。");
        add("bestiary.entity.terra_entity.yellow_slime.desc", "黄史莱姆是简单的胶状生物，见到任何东西都会整个吞下！但消化过程需要很长时间。");
//        add("bestiary.entity.terra_entity.toxic_sludge.desc", "毒泥是普通史莱姆的远亲，它会用强效毒素和看似无害的露齿微笑捕猎猎物。");
        add("bestiary.entity.terra_entity.giant_worm.desc", "巨型蠕虫这些“小土拨鼠”会在地下挖掘隧道，突然袭击专注探索的洞穴者，带来不必要的麻烦。");
//        add("bestiary.entity.terra_entity.digger.desc", "受遍布世界裂缝的远古魔法影响，巨型蠕虫会发生异常的快速生长，形成挖掘怪。");
//        add("bestiary.entity.terra_entity.baby_slime.desc", "史莱姆宝宝紧紧依附在母体上，很少单独出现，一旦母亲受到伤害，它们就会一拥而上围攻敌人。");
        add("bestiary.entity.terra_entity.black_slime.desc", "黑史莱姆是简单的胶状生物，见到任何东西都会整个吞下！但消化过程需要很长时间。");
//        add("bestiary.entity.terra_entity.shimmer_slime.desc", "微光史莱姆在微光中浸泡后，身体被这种神秘液体的力量所浸染，呈现出多彩的外观。");
        add("bestiary.entity.terra_entity.mother_slime.desc", "史莱姆之母对史莱姆物种的生命周期至关重要，这些体型庞大、摇摇晃晃的胶状生物，常带着幼崽栖息在地下深处。");
//        add("bestiary.entity.terra_entity.cochineal_beetle.desc", "胭脂虫生活在黑暗的深层洞穴中，这种大型甲虫因鳞状外骨骼中储存的深红色分泌物而被人们搜寻。");
//        add("bestiary.entity.terra_entity.skeleton_misassembled.desc", "谁说非得有肌肉、皮肤甚至眼球？畸形骷髅仅凭身上的骨头就能行动，杀伤力不亚于有肉体的敌人。");
        add("bestiary.entity.minecraft.skeleton.desc", "谁说非得有肌肉、皮肤甚至眼球？骷髅仅凭身上的骨头就能行动，杀伤力不亚于有肉体的敌人。");
//        add("bestiary.entity.terra_entity.salamander.desc", "蝾螈是栖息在黑暗洞穴中的特殊两栖双足蜥蜴，受到威胁时，会向四周喷射高腐蚀性的酸液。");
//        add("bestiary.entity.terra_entity.skeleton_headache.desc", "谁说非得有肌肉、皮肤甚至眼球？头痛骷髅仅凭身上的骨头就能行动，杀伤力不亚于有肉体的敌人。");
//        add("bestiary.entity.terra_entity.skeleton_pantless.desc", "谁说非得有肌肉、皮肤甚至眼球？无裤骷髅仅凭身上的骨头就能行动，杀伤力不亚于有肉体的敌人。");
        add("bestiary.entity.terra_entity.crawdad.desc", "龙虾是生活在地下的螯虾品种，会沿着洞穴地面快速爬行，用有力的螯钳将猎物撕碎。");
        add("bestiary.entity.confluence.undead_miner.desc", "有证据表明，过去曾有洞穴探险者探索过这些洞穴……也有证据表明，他们在此过程中丧命。");
//        add("bestiary.entity.terra_entity.skeleton_archer.desc", "尽管没有眼睛，骷髅弓箭手仍拥有敏锐的瞄准力，即便与它们保持距离，也难以躲避其燃烧的箭矢。");
        add("bestiary.entity.terra_entity.nymph.desc", "宁芙擅长伪装成迷路的女孩欺骗探险者，随后便会眼中带着嗜血的欲望，发起凶猛攻击。");
        add("bestiary.entity.terra_entity.armored_skeleton.desc", "装甲骷髅是早已覆灭的远征军残部，这些顽强的战士会在自己战死的洞穴中漫无目的地巡逻。");
//        add("bestiary.entity.terra_entity.rock_golem.desc", "岩石巨人是心智迟钝的活石构造体，它会等待疲惫的洞穴生物经过，然后将其砸成碎末。");
//        add("bestiary.entity.terra_entity.tim.desc", "蒂姆生前是一名魔法师，这个有趣的家伙绝不会轻易放弃自己的长袍和巫师帽——除非打赢他。他偏爱温暖的洞穴环境。");
//        add("bestiary.entity.terra_entity.rune_wizard.desc", "符文巫师是蒂姆的哥哥，不仅实力更强，外形也更英俊。他同样喜欢温暖环境，但不喜欢极端高温。");
        add("bestiary.entity.terra_entity.cave_bat.desc", "洞穴蝙蝠体型小巧，难以察觉，飞行轨迹变幻莫测，还常携带狂犬病等疾病。");
//        add("bestiary.entity.terra_entity.giant_bat.desc", "巨型蝙蝠是洞穴蝙蝠的体型更大的近亲，它们更危险，叮咬还会让敌人陷入混乱。");
        add("bestiary.entity.terra_entity.blue_jellyfish.desc", "水中若出现奇怪的刺痛感，可能是无脑的蓝水母释放的致命电流所致，游泳时务必小心。");
        add("bestiary.entity.terra_entity.green_jellyfish.desc", "水中若出现奇怪的刺痛感，可能是无脑的绿水母释放的致命电流所致，游泳时务必小心。");
        add("bestiary.entity.terra_entity.wooden_mimic.desc", "对着宝箱说话不会让人发疯，但如果宝箱回应了你，那可能会让你丧命！不过无论如何，它里面确实藏着稀有宝藏！");
        add("bestiary.entity.terra_entity.golden_mimic.desc", "对着宝箱说话不会让人发疯，但如果宝箱回应了你，那可能会让你丧命！不过无论如何，它里面确实藏着稀有宝藏！");
        add("bestiary.entity.terra_entity.shadow_mimic.desc", "对着宝箱说话不会让人发疯，但如果宝箱回应了你，那可能会让你丧命！不过无论如何，它里面确实藏着稀有宝藏！");
        add("bestiary.entity.terra_entity.giant_shelly.desc", "为了弥补速度慢的缺点，巨型卷壳怪进化出了躲进尖壳中，然后向敌人猛冲的能力。");
//        add("bestiary.entity.terra_entity.lost_girl.desc", "迷失女孩赤裸着身体，带着恐惧伫立在世界深处，仿佛在等待有人将她营救并带回地面。");
//        add("bestiary.entity.terra_entity.granite_golem.desc", "栖息在地下深处花岗岩中的魔法幽魂力量强大，花岗岩巨人便是这类幽魂中呈现人形的品种。");
        add("bestiary.entity.terra_entity.granite_elemental.desc", "土元素会吸收不同物质的特性形成多种形态，花岗精便是以坚硬花岗岩为载体的土元素。");
//        add("bestiary.entity.terra_entity.hoplite.desc", "在已深埋地下的古老文明废墟中，一些投掷长矛的士兵仍在大理石铺就的路径上巡逻。");
//        add("bestiary.entity.terra_entity.medusa.desc", "拥有石化凝视的古老怪物，从她头皮生长如发的蛇群赋予了她这份恐怖力量。");
        add("bestiary.entity.terra_entity.spore_skeleton.desc", "在潮湿洞穴中游荡的骷髅成为发光真菌的宿主，这些真菌大幅增强了它们的战力。");
        add("bestiary.entity.terra_entity.spore_bat.desc", "曾经狂暴的蝙蝠如今角色反转，它们自身被致命的真菌感染，沦为疾病的载体。");
//        add("bestiary.entity.terra_entity.wall_creeper.desc", "爬墙蜘蛛有八条腿、八只眼，更有八种方法将毫无防备的受害者缠入茧中享用。");
//        add("bestiary.entity.terra_entity.black_recluse.desc", "黑隐士有八条腿、八只眼，更有八种方法将毫无防备的受害者缠入茧中享用。");
        add("bestiary.entity.terra_entity.ice_slime.desc", "在极寒环境中停留过久的史莱姆会部分冻结，体表形成一层不断移动的冰层。");
        add("bestiary.entity.minecraft.zombie.frozen.desc", "在雪原生物群系中发现的僵尸，往往裹着冬衣。但这对它们毫无用处——它们依旧是冰冷的尸体！");
        add("bestiary.entity.minecraft.zombie.pink_frozen.desc", "在雪原生物群系中发现的僵尸，往往裹着冬衣。但这对它们毫无用处——它们依旧是冰冷的尸体！");
//        add("bestiary.entity.terra_entity.ice_golem.desc", "暴风雪的危险不止零下低温与刺眼飞雪，还包括被这种冰雪构造体炸得粉身碎骨。");
//        add("bestiary.entity.terra_entity.wolf.desc", "这类凶猛的狼形生物生活在最严酷的气候中，会在漆黑的夜里拼命搜寻食物果腹。");
        add("bestiary.entity.terra_entity.spiked_ice_slime.desc", "这种冰雪史莱姆因长期暴露在严寒中，体内凝结出大量冰碎片，且能以某种方式将这些碎片射向猎物。");
//        add("bestiary.entity.terra_entity.cyan_beetle.desc", "青壳虫耐受极寒的能力极强，其体内含有的蓝色液体可用于纺织品染色，是珍贵的染料来源。");
        add("bestiary.entity.terra_entity.undead_viking.desc", "早在海盗出现之前，便有强大维京人纵横海洋的传说。如今他们的遗骸仍在下方冰冷的洞穴中游荡。");
        add("bestiary.entity.terra_entity.snow_flinx.desc", "小雪怪是外形圆滚的毛茸茸哺乳动物，长着格外突出的大鼻子，体重轻得惊人。");
//        add("bestiary.entity.terra_entity.armored_viking.desc", "最精锐的维京人本该配得上最坚固的盔甲，但从他们如今的亡灵模样来看，这盔甲显然没起到多大作用。");
//        add("bestiary.entity.terra_entity.icy_merman.desc", "人鱼极少远离海洋，一旦迷途闯入寒冷洞穴，便会化为冰冷的不死鱼人。");
        add("bestiary.entity.terra_entity.ice_bat.desc", "蝙蝠本就足够麻烦，而冰雪蝙蝠只需一碰就能将生物的肉体冻成硬块，让猎物彻底失去防御能力。");
//        add("bestiary.entity.terra_entity.ice_elemental.desc", "在极寒之地聚集的浓厚强力魔法，会使水元素转化为冰雪精。它们周身的冰霜碎片能冻结万物。");
        add("bestiary.entity.terra_entity.ice_mimic.desc", "对着宝箱说话不会让人发疯，但要是宝箱回了话，那很可能会让人丧命！不过无论如何，它里面确实藏着稀有宝藏！");
//        add("bestiary.entity.terra_entity.ice_tortoise.desc", "冰雪陆龟和它们的丛林近亲一样，是远超预期的可怕威胁，拥有惊人的速度与机动性。");
//        add("bestiary.entity.terra_entity.vulture.desc", "秃鹰是为适应沙漠酷热而生的鸟类食腐者，任何靠近它们腐食的生物，都会被其啄咬撕扯。");
        add("bestiary.entity.terra_entity.desert_slime.desc", "沙漠环境极度干旱，而沙史莱姆通过化为一团“活沙”，成功适应了这种恶劣条件。");
//        add("bestiary.entity.terra_entity.antlion_larva.desc", "刚从卵中孵化的蚁狮幼虫绝不可轻视，即便尚处幼年，它们的攻击性也极强。");
//        add("bestiary.entity.terra_entity.giant_antlion_charger.desc", "巨型蚁狮马是蚁狮族群的士兵，会以惊人的速度凶猛地追击入侵者。");
        add("bestiary.entity.terra_entity.mummy.desc", "外界力量改变了沙漠的形态，那些安息于此的生灵——无论善恶——如今都苏醒过来，肆意残杀。");
        add("bestiary.entity.terra_entity.ghoul.desc", "食尸鬼是被干旱环境保存下来的干枯僵尸躯壳，在沙丘之下的黑暗洞穴中四处游荡。");
//        add("bestiary.entity.terra_entity.basilisk.desc", "蛇蜥怪如岩石般坚固，这类蜥蜴状生物在沙漠中搜寻猎物，坚硬的躯体让它们成为难以对付的威胁。");
        add("bestiary.entity.terra_entity.tomb_crawler.desc", "沙漠是这片土地上最大型蠕虫的栖息地之一，这种墓穴爬虫对粗心的探险者有着极大的胃口。");
//        add("bestiary.entity.terra_entity.antlion.desc", "蚁狮筑巢时会潜藏在地表之下，若有入侵者威胁到它们的卵，便会喷射坚硬的沙团进行反击。");
        add("bestiary.entity.terra_entity.sand_poacher.desc", "这些异常巨大的蝎子已进化出沿墙壁快速追击猎物的能力，其锋利的毒尾是致命武器。");
        add("bestiary.entity.terra_entity.giant_antlion_swarmer.desc", "巨型蚁狮蜂会警惕地巡视巢穴，一旦有人威胁到它们的卵，便会拼死守护。");
//        add("bestiary.entity.terra_entity.antlion_charger.desc", "蚁狮马是蚁狮族群的士兵，会以惊人的速度凶猛地追击入侵者。");
//        add("bestiary.entity.terra_entity.dune_splicer.desc", "沙虫是世界上体型最大、最致命的蠕虫。经远古魔法强化后，它吞噬一个鲜活泰拉瑞亚生物的速度，比猎物反应过来的速度还要快。");
//        add("bestiary.entity.terra_entity.angry_tumbler.desc", "这团风滚草被强风吹得在沙漠里四处翻滚，早已满心怒火。它顺风滚动的速度远快于逆风时。");
        add("bestiary.entity.terra_entity.antlion_swarmer.desc", "蚁狮蜂会警惕地巡视巢穴，一旦有人威胁到它们的卵，便会拼死守护。");
//        add("bestiary.entity.terra_entity.sand_elemental.desc", "最强烈的沙尘暴会召唤出强大的土元素——沙尘精。以雌性形态显现的它，能召唤龙卷风撕碎一切。");
//        add("bestiary.entity.terra_entity.sand_shark.desc", "远古时期曾有一条咸水河贯穿沙漠，如今这些沙鲨已进化出在干燥沙层中生存的能力。");
        add("bestiary.entity.terra_entity.crab.desc", "这种生活在海岸的硬壳生物，能轻易剪断人的脚趾，甚至造成更严重的伤害，绝不可轻视。");
//        add("bestiary.entity.terra_entity.sea_snail.desc", "这种异常巨大的海蜗牛栖息在深海之中，其分泌的黏液可被加工成紫色染料。");
        add("bestiary.entity.terra_entity.shark.desc", "这些海洋掠食者一旦嗅到血腥味，便会陷入疯狂的追逐，既不知疲倦也无法阻挡。");
//        add("bestiary.entity.terra_entity.squid.desc", "这种长有触手的海洋生物，遇袭时会喷出浓稠的黑色墨汁。人们会收集这种墨汁用于装饰用途。");
        add("bestiary.entity.terra_entity.pink_jellyfish.desc", "水中若出现奇怪的刺痛感，很可能是无脑的粉水母释放的致命电击。游泳时务必小心。");
        add("bestiary.entity.terra_entity.jungle_slime.desc", "丛林史莱姆是简单的胶状生物，见到任何东西都会整个吞下！但消化过程需要很长时间。");
        add("bestiary.entity.terra_entity.snatcher.desc", "抓人草是长有锋利牙齿的肉食植物，偏好人类血肉。它能潜藏在泥土中，攻击范围远超想象。");
//        add("bestiary.entity.terra_entity.giant_flying_fox.desc", "巨型飞狐是蝙蝠的巨型近亲，仅在丛林中出现，会在夜空中搜寻猎物。");
        add("bestiary.entity.terra_entity.derpling.desc", "这些身披蓝宝石色外壳的巨型跳蚤，会不停地跳跃移动，短短几秒内就能吸干一个人的血液。");
        add("bestiary.entity.terra_entity.spiked_jungle_slime.desc", "尖刺丛林史莱姆因长期吞食丛林中的毒素与荆棘，体表布满了带毒的尖刺。");
//        add("bestiary.entity.terra_entity.lac_beetle.desc", "紫胶虫在茂密的地下植被中繁衍生息，其分泌物能将多种材料染成美丽的紫色。");
//        add("bestiary.entity.terra_entity.doctor_bones.desc", "骷髅博士这个特殊的僵尸，擅长寻找历史文物，却对蛇类有着极大的厌恶。");
//        add("bestiary.entity.terra_entity.bee.desc", "在丛林各处的蜂巢与巢穴中，都能见到这种蜜蜂，它们会随时蜂拥袭击探险者。");
//        add("bestiary.entity.terra_entity.bee_larger.desc", "在丛林各处的蜂巢与巢穴中，都能见到这种较大的蜜蜂，它们会随时蜂拥袭击探险者。");
        add("bestiary.entity.terra_entity.hornet_stingy.desc", "带毒刺的黄蜂是活跃在丛林深处的攻击性飞虫，能从极远的距离高速射出有毒的螫针。");
        add("bestiary.entity.terra_entity.hornet_spikey.desc", "带尖刺的黄蜂是活跃在丛林深处的攻击性飞虫，能从极远的距离高速射出有毒的螫针。");
        add("bestiary.entity.terra_entity.hornet.desc", "黄蜂是活跃在丛林深处的攻击性飞虫，能从极远的距离高速射出有毒的螫针。");
        add("bestiary.entity.terra_entity.hornet_fatty.desc", "肥胖的黄蜂是活跃在丛林深处的攻击性飞虫，能从极远的距离高速射出有毒的螫针。");
        add("bestiary.entity.terra_entity.hornet_honey.desc", "沾蜜的黄蜂是活跃在丛林深处的攻击性飞虫，能从极远的距离高速射出有毒的螫针。");
        add("bestiary.entity.terra_entity.hornet_leafy.desc", "带叶的黄蜂是活跃在丛林深处的攻击性飞虫，能从极远的距离高速射出有毒的螫针。");
//        add("bestiary.entity.terra_entity.moss_hornet.desc", "丛林中能量充沛的植物已与这类苔藓黄蜂融合，强化了它们的外骨骼与毒刺。");
//        add("bestiary.entity.terra_entity.moth.desc", "极少数情况下，接触丛林毒素会使某些飞蛾发生变异，体型变得异常巨大。它们死亡时会释放出珍贵的粉末。");
        add("bestiary.entity.terra_entity.man_eater.desc", "食人怪是长有锋利牙齿的肉食植物，偏好人类血肉。它能潜藏在泥土中，攻击范围远超想象。");
//        add("bestiary.entity.terra_entity.angry_trapper.desc", "当食人怪吞食足够多的人类血肉后，会像结茧般蜕变，化为更致命的愤怒捕手。");
        add("bestiary.entity.terra_entity.jungle_bat.desc", "这些烦人的小型丛林蝙蝠绝不可轻视，一旦被这群尖牙啮齿动物包围，便只有死路一条。");
        add("bestiary.entity.terra_entity.piranha.desc", "仅凭一条食人鱼，就足以轻易夺走一条生命。不幸的是，它们还喜欢成群围攻猎物！真是“精彩”的生命法则。");
//        add("bestiary.entity.terra_entity.angler_fish.desc", "有些琵琶鱼喜欢埋伏等待猎物上门，而这类琵琶鱼则热衷于主动追击水下的猎物。");
        add("bestiary.entity.terra_entity.arapaima.desc", "巨骨舌鱼在靠近不稳定魔法矿脉的丛林水域中生存，这种环境让它们变得异常强壮且充满敌意。");
//        add("bestiary.entity.terra_entity.giant_tortoise.desc", "没人会把巨型陆龟当回事——直到它们像个旋转的死亡刺球一样，从空中猛冲下来。");
//        add("bestiary.entity.terra_entity.jungle_creeper.desc", "“小小蜘蛛爬藤蔓，倒霉探险掉下来，蜘蛛饱餐真痛快。故事完。”");
        add("bestiary.entity.terra_entity.meteor_head.desc", "陨石撞击地表后，碎片会散落各处等待拾取。但有些碎片是“活的”，会主动发起攻击。");
        add("bestiary.entity.terra_entity.dungeon_slime.desc", "地牢史莱姆通过吸收地牢中的诅咒能量变得强大，且似乎对钥匙有着特殊的吸引力。");
        add("bestiary.entity.terra_entity.anger_bones.desc", "愤怒骷髅怪是受不死诅咒的原地牢居民，在地牢大厅中永无休止地游荡，寻找宣泄无尽怒火的目标。");
        add("bestiary.entity.terra_entity.short_bones.desc", "矮骷髅是受不死诅咒的原地牢居民，在地牢大厅中永无休止地游荡，寻找宣泄无尽怒火的目标。");
        add("bestiary.entity.terra_entity.big_bones.desc", "大骷髅是受不死诅咒的原地牢居民，在地牢大厅中永无休止地游荡，寻找宣泄无尽怒火的目标。");
        add("bestiary.entity.terra_entity.big_anger_bones.desc", "大型愤怒骷髅怪是受不死诅咒的原地牢居民，在地牢大厅中永无休止地游荡，寻找宣泄无尽怒火的目标。");
        add("bestiary.entity.terra_entity.big_muscle_anger_bones.desc", "大块头愤怒骷髅怪是受不死诅咒的原地牢居民，在地牢大厅中永无休止地游荡，寻找宣泄无尽怒火的目标。");
        add("bestiary.entity.terra_entity.big_helmet_anger_bones.desc", "戴大头盔的愤怒骷髅怪是受不死诅咒的原地牢居民，在地牢大厅中永无休止地游荡，寻找宣泄无尽怒火的目标。");
//        add("bestiary.entity.terra_entity.blue_armored_bones_mace.desc", "持锤矛的蓝装甲骷髅属于“行军骷髅”，它们纪律严明、锲而不舍地追求目标，会撕碎一切挡路的事物或生物。");
//        add("bestiary.entity.terra_entity.skeleton_sniper.desc", "骷髅狙击手是拥有鹰眼的神射手，任何目标都逃不过它们的准星。它们生前是精英部队的一员。");
//        add("bestiary.entity.terra_entity.tactical_skeleton.desc", "骷髅特警配备厚重盔甲与强力霰弹枪，显然是为围城战做好了准备。它们生前是精英部队的一员。");
//        add("bestiary.entity.terra_entity.skeleton_commando.desc", "骷髅突击手以火箭为动力、以愤怒为燃料，这些被诅咒的骷髅偏爱用“核弹级”手段解决问题。它们生前是精英部队的一员。");
//        add("bestiary.entity.terra_entity.hell_armored_bones.desc", "地狱装甲骷髅属于“熔火军团”，其炽热光芒辨识度极高。它们手持烧红的武器，在挡路者中开辟出一条火焰通路。");
//        add("bestiary.entity.terra_entity.rusty_armored_bones_sword_no_armor.desc", "无甲持剑的生锈装甲骷髅属于“锈蚀连队”，其武器因长期使用与疏于保养而布满豁口，会给敌人造成严重的流血伤口。");
//        add("bestiary.entity.terra_entity.rusty_armored_bones_flail.desc", "持连枷的生锈装甲骷髅属于“锈蚀连队”，其武器因长期使用与疏于保养而布满豁口，会给敌人造成严重的流血伤口。");
