//        add("bestiary.entity.terra_entity.blue_armored_bones_no_pants.desc", "无裤的蓝装甲骷髅属于“行军骷髅”，它们纪律严明、锲而不舍地追求目标，会撕碎一切挡路的事物或生物。");
//        add("bestiary.entity.terra_entity.hell_armored_bones_sword.desc", "持剑的地狱装甲骷髅属于“熔火军团”，其炽热光芒辨识度极高。它们手持烧红的武器，在挡路者中开辟出一条火焰通路。");
//        add("bestiary.entity.terra_entity.rusty_armored_bones_axe.desc", "持斧的生锈装甲骷髅属于“锈蚀连队”，其武器因长期使用与疏于保养而布满豁口，会给敌人造成严重的流血伤口。");
//        add("bestiary.entity.terra_entity.blue_armored_bones_sword.desc", "持剑的蓝装甲骷髅属于“行军骷髅”，它们纪律严明、锲而不舍地追求目标，会撕碎一切挡路的事物或生物。");
//        add("bestiary.entity.terra_entity.bone_lee.desc", "传说几百年前，世界的暗影中曾有一个忍者氏族。如今看来，他们早已化为骷髅李，不复当年。");
//        add("bestiary.entity.terra_entity.paladin.desc", "在遥远的过去，这些强大的圣骑士曾守护着一座繁荣的城市，直到一场巨大的诅咒降临在他们身上，使他们化为不死生物。");
        add("bestiary.entity.terra_entity.dark_caster.desc", "暗黑法师注定要看守地牢，它们会通过瞬移迷惑猎物，随后用一股水流击倒对方。");
//        add("bestiary.entity.terra_entity.diabolist_red.desc", "持红色魔教旗的魔教徒，能操控与地狱同等炽热的火焰，在灼热的炼狱之火中吞噬一切。");
//        add("bestiary.entity.terra_entity.diabolist_white.desc", "持白色魔教旗的魔教徒，能操控与地狱同等炽热的火焰，在灼热的炼狱之火中吞噬一切。");
//        add("bestiary.entity.terra_entity.necromancer.desc", "生前，这些巫士便佩戴着所属教团的死灵标旗，即便化为亡灵，这份印记也将永远伴随它们……直至永恒。");
//        add("bestiary.entity.terra_entity.ragged_caster.desc", "褴褛邪教徒法师身为褴褛兄弟会成员，能施展被诅咒的魔法，让受害者在彻底的黑暗中无助地迷失方向。");
//        add("bestiary.entity.terra_entity.necromancer_armored.desc", "生前，这些身着盔甲的巫士便佩戴着所属教团的死灵标旗，即便化为亡灵，这份印记也将永远伴随它们……直至永恒。");
//        add("bestiary.entity.terra_entity.ragged_caster_open_coat.desc", "敞开外衣的褴褛邪教徒法师身为褴褛兄弟会成员，能施展被诅咒的魔法，让受害者在彻底的黑暗中无助地迷失方向。");
        add("bestiary.entity.terra_entity.cursed_skull.desc", "受黑暗仪式影响，这颗诅咒骷髅头已能自行漂浮移动，主动追逐活物。一旦被它触碰，受害者将失去所有防御能力。");
//        add("bestiary.entity.terra_entity.giant_cursed_skull.desc", "没人知晓巨型诅咒骷髅头的来历，但与体型较小的同类一样，它们会用魔法搜寻活人，并对其施加诅咒。");
        add("bestiary.entity.terra_entity.dungeon_guardian.desc", "地牢守卫是镇守地牢大门的致命哨兵，任何被判定为“无资格进入”的生物，都绝无可能通过它的防线！");
//        add("bestiary.entity.terra_entity.dungeon_spirit.desc", "在地牢中，部分实力较强的被诅咒住民体内，有时会聚集起高浓度的灵气，最终化为地牢幽魂。");
        add("bestiary.entity.terra_entity.lava_slime.desc", "受地狱高温影响，熔岩史莱姆已具备熔岩的特性——不仅体表灼热，且韧性极强，想要击杀它们既困难又危险。");
//        add("bestiary.entity.terra_entity.tortured_soul.desc", "痛苦亡魂因毕生贪婪的野心，被判处永恒的惩罚，在漫长岁月中早已被腐化，沦为彻底的恶魔形态。");
        add("bestiary.entity.terra_entity.bone_serpent.desc", "曾有威猛的蛇形巨龙统治地狱，但很久以前它们便蜕去了黑曜石龙鳞，如今仅剩下一具具骨骼残骸，化为骨蛇游荡。");
        add("bestiary.entity.terra_entity.wither_bone_serpent.desc", "灵魂沙峡谷的高浓度灵魂使得这些蛇形巨龙的残骸变得更加致命");
        add("bestiary.entity.terra_entity.fire_imp.desc", "火焰小鬼是蕴含地狱魔法的低级恶魔，既能施展瞬移躲避攻击，又能向敌人投掷幻影火球造成伤害。");
        add("bestiary.entity.terra_entity.hellbat.desc", "狂躁易怒、飞行迅捷又惹人厌烦的飞行动物已够麻烦，而浑身燃烧着地狱之火的地狱蝙蝠，无疑是雪上加霜！");
        add("bestiary.entity.terra_entity.demon.desc", "恶魔是地狱的主力步兵，与火焰小鬼等低级同类不同，它们掌握的是暗影魔法，而非基础的地狱火焰魔法。");
        add("bestiary.entity.terra_entity.voodoo_demon.desc", "身为高阶恶魔的巫毒恶魔，能持有“天选者”的巫毒娃娃——而这具娃娃的灵魂，与世界守卫者本身紧密相连。");
        add("bestiary.entity.terra_entity.lava_bat.desc", "有什么比狂躁、恼人、疾飞的飞行啮齿动物更糟糕呢？显然，答案之一是：浑身冒火的熔岩蝙蝠！");
//        add("bestiary.entity.terra_entity.red_devil.desc", "红魔鬼作为精英恶魔，能召唤出蕴含强大黑魔法的长矛，对任何胆敢闯入其领地的生物而言，都是极具威胁的存在。");
        add("bestiary.entity.terra_entity.wyvern.desc", "飞龙是与古老灵魂一同被释放的巨型类龙生物，凭借无可匹敌的力量统治着整片天空。");
        add("bestiary.entity.terra_entity.harpy.desc", "鸟妖是长有翅膀的亚人女性，会用锋利如刀的羽毛刺穿入侵者，以此守护自己的领地。");
//        add("bestiary.entity.terra_entity.martian_probe.desc", "异界生物察觉到这颗星球上的力量正不断增强，便派出具备太空时代技术的火星探测器，用于扫描寻找先进生命形态。");
//        add("bestiary.entity.terra_entity.slimeling.desc", "小史莱姆是受伤腐化史莱姆脱落的残块，即便只剩部分躯体仍能活动，不仅能发起攻击，还具备群体作战的优势。");
        add("bestiary.entity.terra_entity.corrupt_slime.desc", "腐化史莱姆被腐化之力深度浸染，与未受污染的同类不同，即便被切割成小块，每一部分都能独立存活。");
        add("bestiary.entity.terra_entity.eater_of_souls.desc", "噬魂怪诞生于腐化之地，是纯粹由恶意构成的生物，其唯一本能便是追逐、惩罚并杀戮一切活物。");
//        add("bestiary.entity.terra_entity.corruptor.desc", "腐化者是腐化之地孕育的腐烂生物，如同癌症般不断变异生长，最终会进化为体型更大、能喷射酸液的致命形态。");
        add("bestiary.entity.terra_entity.devourer.desc", "吞噬怪是形似蠕虫的恐怖生物，也是腐化之地最青睐的造物，常会在毫无防备的受害者脚下挖掘通道，发动突袭。");
//        add("bestiary.entity.terra_entity.world_feeder.desc", "远古魔法释放的黑暗力量催生了世界吞噬怪，同时也孕育出吞世怪这类体型更小、但同样致命的蠕虫生物。");
//        add("bestiary.entity.terra_entity.clinger.desc", "在最黑暗的腐化之地深处，栖息着爬藤怪这种恐怖生物——它们长有触手，能从岩壁中延伸而出，还会喷射诅咒火焰。");
//        add("bestiary.entity.terra_entity.slimer.desc", "恶翅史莱姆不知从何处获得了翅膀，从而拥有飞行能力。但这对翅膀十分脆弱，受外力撞击便会脱落，使其失去飞行能力。");
//        add("bestiary.entity.terra_entity.cursed_hammer.desc", "诅咒锤因对腐化的极致仇恨而被赋予魔法，会自行挥舞旋转，试图粉碎所有拥有生命的物体。");
        add("bestiary.entity.terra_entity.corrupt_mimic.desc", "落入腐化之地的宝箱怪会进化为腐化宝箱怪，体型与实力大幅提升。通过外力作用，也能从普通宝箱中强制催生它们。");
        add("bestiary.entity.terra_entity.jungle_mimic.desc", "这些古老的宝箱怪处于某个世界的丛林中，可惜埋藏的“宝物”实在过于特殊。不得不怀疑埋藏者的用意");
//        add("bestiary.entity.terra_entity.pigron_corrupt.desc", "腐化猪龙是难以捉摸的龙猪杂交生物，即便体型圆胖，仍具备出色的潜行能力。目前尚未知晓它们的起源。");
//        add("bestiary.entity.terra_entity.bone_biter.desc", "噬骨沙鲨的祖先生活在远古时期流经沙漠的咸水河中，如今已进化出在干燥沙漠中生存的能力。");
        add("bestiary.entity.terra_entity.dark_mummy.desc", "暗黑木乃伊原本是安息在沙漠中的逝者，受外界力量改变沙漠形态的影响，无论生前善恶，如今都化为亡灵苏醒，肆意残杀。");
        add("bestiary.entity.terra_entity.vile_ghoul.desc", "腐恶食尸鬼被腐化之力扭曲，体内会渗出恶心的绿色胆汁，这种胆汁接触皮肤便会燃烧，用诅咒火焰灼烧猎物。");
        add("bestiary.entity.terra_entity.crimson_slime.desc", "猩红史莱姆的躯体由凝结的血肉构成，会主动寻找并吞噬生物，为猩红之地提供更多扩张所需的原材料。");
        add("bestiary.entity.terra_entity.face_monster.desc", "脸怪是无情且贪婪的变异生物，与它们正面抗衡绝非明智之举——其嘴巴大到足以吞噬任何眼前的事物。");
        add("bestiary.entity.terra_entity.crimera.desc", "猩红喀迈拉是猩红之地最常见的恐怖造物，始终被无尽的饥饿驱使，执着于吞噬纯净的生命与物体。");
//        add("bestiary.entity.terra_entity.blood_feeder.desc", "嗜血怪与食人鱼类似，是成群出没的嗜血鱼类。它们诞生于受污染的血液中，对鲜血的渴望极为强烈。");
//        add("bestiary.entity.terra_entity.blood_jelly.desc", "血水母原本是普通水母，在猩红之地的血腥水域中被感染，沦为猩红力量的傀儡，参与到吞噬一切的行动中。");
//        add("bestiary.entity.terra_entity.floaty_gross.desc", "恶心浮游怪是来自猩红之地最深处的浮游恐怖生物，毫无疑问，它们既符合“漂浮”的特征，也完全配得上“恶心”的形容。");
//        add("bestiary.entity.terra_entity.ichor_sticker.desc", "灵液黏黏怪是形似乌贼的丑恶生物，体内充满强效灵液，会向猎物喷射具有腐蚀性的生物流体。");
//        add("bestiary.entity.terra_entity.crimson_axe.desc", "猩红斧被猩红之地的集体意识所操控，能凭自身意志移动，挥砍并击杀所有阻挡猩红扩张的敌人。");
        add("bestiary.entity.terra_entity.blood_crawler.desc", "血爬虫是受猩红巢穴影响的蜘蛛，与普通蜘蛛的独立行动不同，它们会协同作战，共同蚕食生命。");
        add("bestiary.entity.terra_entity.herpling.desc", "蹦蹦兽是形似鼻涕虫的疯狂恶魔，行动亢奋且残暴，对血肉有着无法抑制的渴望，始终为猩红部落效力。");
        add("bestiary.entity.terra_entity.crimson_mimic.desc", "被猩红之力蛊惑的宝箱怪会进化为猩红宝箱怪，实力得到显著增强。通过外力作用，也能从普通宝箱中强制催生它们。");
//        add("bestiary.entity.terra_entity.pigron_crimson.desc", "猩红猪龙是难以捉摸的龙猪杂交生物，即便体型圆胖，仍具备出色的潜行能力。目前尚未知晓它们的起源。");
//        add("bestiary.entity.terra_entity.flesh_reaver.desc", "戮血沙鲨的祖先生活在远古时期流经沙漠的咸水河中，如今已进化出在干燥沙漠中生存的能力。");
        add("bestiary.entity.terra_entity.blood_mummy.desc", "血木乃伊的躯体中残留着大量滴血的有机物，与其他木乃伊相比，这些有机物的保存状态要好得多。");
        add("bestiary.entity.terra_entity.tainted_ghoul.desc", "红染食尸鬼被猩红之力感染，嘴巴会不断渗出邪恶灵液，每一次啃咬都会削弱敌人的防御能力。");
        add("bestiary.entity.terra_entity.dark_lamia.desc", "当沙漠洞穴的黑暗中出现发光的红色眼眸时，一切都已太晚——拉弥亚早已锁定了自己的猎物。");
//        add("bestiary.entity.terra_entity.desert_spirit.desc", "沙漠幽魂原本是友善的沙漠精灵，受远古魔法影响心智被腐化，从 lamps 中挣脱而出，变得充满敌意。");
//        add("bestiary.entity.terra_entity.rainbow_slime.desc", "彩虹史莱姆是蕴含福佑之力的胶状怪物，身体闪耀着绚丽的彩虹色光芒。正因如此，它们需要持续摄入液体才能维持形态。");
        add("bestiary.entity.terra_entity.pixie.desc", "妖精是体型更大、光芒更盛的仙灵变种，能为神圣之地带来更多福佑之光，助力净化被腐化或猩红污染的土地。");
//        add("bestiary.entity.terra_entity.gastropod.desc", "腹足怪原本是夜行史莱姆，受神圣福佑影响进化为漂浮的蜗牛状生物，能向敌人喷射强大的光束。");
//        add("bestiary.entity.terra_entity.unicorn.desc", "独角兽是长有独角的威严生物，会在神圣之地上愤怒地奔袭，搜寻并清除所有入侵这片纯净土地的异类。");
        add("bestiary.entity.terra_entity.luminous_slime.desc", "夜明史莱姆因暴露在神圣之地的水晶光芒中，自身也开始散发同样的光芒，在黑暗环境中显得格外耀眼。");
//        add("bestiary.entity.terra_entity.chaos_elemental.desc", "混沌精原本是普通生物，受神圣福佑注入后发生异变，会携带着难以控制的发光能量，疯狂追逐周围的活物。");
//        add("bestiary.entity.terra_entity.illuminant_bat.desc", "夜明蝙蝠受神圣之地的棱镜光芒祝福，身体呈现亮粉色，飞行时会在黑暗的地下空间划出一道模糊的光影弧线。");
//        add("bestiary.entity.terra_entity.enchanted_sword.desc", "附魔剑被神圣水晶的福佑之光赋予生命，会主动劈砍一切邪恶之物，以净化世界为己任。");
        add("bestiary.entity.terra_entity.hallowed_mimic.desc", "受神圣福佑加持的宝箱怪会进化为神圣宝箱怪，能量大幅涌动、实力显著提升。通过外力作用，也能从普通宝箱中强制催生它们。");
//        add("bestiary.entity.terra_entity.pigron.desc", "猪龙是难以捉摸的龙猪杂交生物，即便体型圆胖，仍具备出色的潜行能力。目前尚未知晓它们的起源。");
//        add("bestiary.entity.terra_entity.crystal_thresher.desc", "水晶沙鲨的祖先生活在远古时期流经沙漠的咸水河中，如今已进化出在干燥沙漠中生存的能力。");
        add("bestiary.entity.terra_entity.light_mummy.desc", "光明木乃伊原本是安息在沙漠中的逝者，受外界力量改变沙漠形态的影响，无论生前善恶，如今都化为亡灵苏醒，肆意残杀。");
        add("bestiary.entity.terra_entity.dreamer_ghoul.desc", "神梦食尸鬼被神圣之地净化后，唾液带有迷幻效果，能让受害者产生幻象，陷入困惑并分散注意力。");
        add("bestiary.entity.terra_entity.light_lamia.desc", "当地下沙漠洞穴的黑暗中出现发光的红色眼眸时，一切都已太晚——地下沙漠的拉弥亚早已锁定了自己的猎物。");
        add("bestiary.entity.terra_entity.spore_zombie.desc", "控制孢子僵尸（蘑菇）心智的真菌只有一个目标：吞噬大脑！这与僵尸本身的本能不谋而合，对僵尸而言极为“方便”。");
        add("bestiary.entity.terra_entity.hat_spore_zombie.desc", "控制孢子僵尸（帽子蘑菇）心智的真菌只有一个目标：吞噬大脑！这与僵尸本身的本能不谋而合，对僵尸而言极为“方便”。");
//        add("bestiary.entity.terra_entity.anomura_fungus.desc", "歪尾真菌是形似螃蟹的生物，在发光蘑菇田里四处爬行，全身被真菌孢子严重侵染。");
//        add("bestiary.entity.terra_entity.mushi_ladybug.desc", "蘑菇瓢虫是极具攻击性的瓢虫变种，在发光蘑菇附近能自在生存，与真菌形成共生关系。");
//        add("bestiary.entity.terra_entity.fungi_bulb.desc", "当发光真菌准备扩散时，真菌球怪便会生长成熟，将孢子传播到其他区域和宿主身上，助力真菌繁衍。");
//        add("bestiary.entity.terra_entity.shadowflame_apparition.desc", "暗影焰幻鬼是扭曲哥布林祖先的强大精神残魂，通过强力召唤仪式被唤醒，能操控暗影焰魔法。");
//        add("bestiary.entity.terra_entity.old_ones_skeleton.desc", "撒旦骷髅是由暗黑魔法师从地底召唤出的骷髅军团，它们会忠诚地遵循主人的意志行动。");
//        add("bestiary.entity.terra_entity.etherian_goblin.desc", "埃特尼亚哥布林是来自埃特尼亚的独特哥布林物种，与泰拉瑞亚本土哥布林无亲缘关系，是撒旦军队的凶残步兵。");
//        add("bestiary.entity.terra_entity.etherian_goblin_bomber.desc", "埃特尼亚哥布林投弹手会不顾一切地投掷炸弹，以狂热的姿态为撒旦军队效力，是军队中的工兵角色。");
//        add("bestiary.entity.terra_entity.kobold.desc", "小妖魔的身体装载着爆炸装置，完全不顾自身安全，会主动引爆自己，试图与敌人同归于尽。");
//        add("bestiary.entity.terra_entity.etherian_javelin_thrower.desc", "埃特尼亚标枪投掷怪体型庞大、动作笨拙，但它们投掷的标枪锋利无比，且瞄准精准，极具致命性。");
//        add("bestiary.entity.terra_entity.wither_beast.desc", "枯萎兽能通过背部的水晶释放削弱防御的光环，且在扎根不动时，自身能快速恢复生命值。");
//        add("bestiary.entity.terra_entity.drakin.desc", "德拉克龙是为撒旦军队效力的埃特尼亚爬行动物，实力强悍，能向敌人喷射致命的紫色火焰。");
//        add("bestiary.entity.terra_entity.ogre.desc", "食人魔是撒旦军队中的高大亚人生物，体型魁梧、力量与耐力深不可测，手持一根巨大的棍棒作为武器。");
//        add("bestiary.entity.terra_entity.kobold_glider.desc", "小妖魔滑翔怪将“爆炸战术”提升到了新高度，它们会滑翔于空中，从上方对敌人发动致命的自爆攻击。");
//        add("bestiary.entity.terra_entity.etherian_wyvern.desc", "埃特尼亚飞龙拥有多样的外形与体型，行为模式更接近蝙蝠，与泰拉瑞亚本土威风凛凛的飞龙截然不同。");
//        add("bestiary.entity.terra_entity.dark_mage.desc", "黑暗魔法师是来自埃特尼亚的小型浮空巫士，擅长操控黑魔法，还能为撒旦军队召唤新的仆从。");
//        add("bestiary.entity.terra_entity.betsy.desc", "双足翼龙是凶残的埃特尼亚毒龙，它率领着撒旦军队的仆从，成功抵达并入侵了泰拉瑞亚世界。");
//        add("bestiary.entity.terra_entity.etherian_lightning_bug.desc", "埃特尼亚荧光虫并非只因发光美丽而得名——它们还能向敌人发射骇人的电流，具备强大的攻击能力。");
//        add("bestiary.entity.terra_entity.pirate_deadeye.desc", "海盗神射手的“死眼”称号来源成谜：有人说是指它们精准的瞄准能力，也有人说是因为它们的一只眼睛早已“死去”，如同它们的猎物一般。");
//        add("bestiary.entity.terra_entity.pirate_deckhand.desc", "海盗水手要么在船上清洗甲板上的海草与麦芽酒污渍，要么就用毫无防备的泰拉瑞亚人的脸来“擦拭”地面。");
