//        add("bestiary.entity.terra_entity.ray_gunner.desc", "激光枪手是火星入侵部队的精英专家，配备着精度更高、杀伤力更强的激光步枪，实际作战定位相当于狙击手。");
//        add("bestiary.entity.terra_entity.martian_engineer.desc", "火星工程师是战斗能力较弱的火星士兵，会凭借自身的机械天赋被派往战场，负责建造防御炮塔。");
//        add("bestiary.entity.terra_entity.martian_officer.desc", "火星军官没有装备进攻性武器，因此更倾向于采取防御策略，专注于将战术指令传递给下属士兵。");
//        add("bestiary.entity.terra_entity.gigazapper.desc", "电击怪是在近距离战斗中展现出巨大潜力的火星人，装备着能将物体原子化的强大能量长矛。");
//        add("bestiary.entity.terra_entity.scutlix.desc", "鳞甲怪原产于火星，功能与马匹相似——区别在于，它们的眼睛能发射激光。");
//        add("bestiary.entity.terra_entity.gray_grunt.desc", "灰咕噜是被征召入伍的火星人，那些未达到战斗标准的个体，会被赤手空拳派往战场充当炮灰，分散敌人注意力。");
//        add("bestiary.entity.terra_entity.martian_walker.desc", "火星走妖是火星科技的奇迹造物，由最坚硬的金属打造而成，并注入了生物成分增强战力。");
